@charset "UTF-8";
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap");
/*======================================
Variables globales (Harmonisées)
======================================*/
:root {
  --font-primary: "Poppins", sans-serif;
  /* Couleurs Typographie */
  --color-text-dark: #39444D;
  --color-text-gray: #6B7280;
  --color-text-light: #9CA3AF;
  /* Couleurs UI */
  --color-bg: #ffffff;
  --color-bg-gray-light: #F9FAFB;
  --color-border: #E5E7EB;
  --color-pill-true-bg: #ECFDF5;
  --color-pill-true-text: #007A56;
  --color-primary: #82DB34;
  --color-primary-hover: #75C62F;
  --color-secondary: #204A83;
  --color-secondary-hover: #163F6B;
  --radius-main: 12px;
  --radius-sm: 8px;
  --radius-pill: 20px;
  --spacing: 1.5rem;
  --spacing-half: 0.75rem;
  --shadow-card: 0 -4px 10px rgba(0, 0, 0, 0.03), 0 4px 6px -1px rgba(0, 0, 0, 0.05);
}

body {
  margin: 0;
  padding: 10px;
  font-family: var(--font-primary);
  background-color: transparent;
  color: var(--color-text-dark);
}

/*======================================
  Conteneur Principal (Bottom Bar)
======================================*/
.cta-offer {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-half);
  padding: var(--spacing);
  width: 100%;
  max-width: 1000px;
  margin: 0 auto;
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-main);
  box-shadow: var(--shadow-card);
  box-sizing: border-box;
}

/*======================================
  Bouton Document (Haut Droite)
======================================*/
.cta--offer__documents {
  display: flex;
  align-self: flex-end;
}

/*======================================
  Grille Principale (Band)
======================================*/
.band {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
  width: 100%;
  align-items: center;
}

.band-item {
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.band-item-right {
  align-items: flex-end;
}

.band-item-left {
  align-items: flex-start;
}

/*======================================
  Typographie Assureur / Formule
======================================*/
.cta-offer__title {
  color: var(--color-text-dark);
  font-size: 1.2rem;
  font-weight: 700;
  line-height: 1.2;
}

.cta-offer__name {
  color: var(--color-text-light);
  font-size: 0.95rem;
  font-weight: 500;
  margin-top: 4px;
}

/*======================================
  Prix & Economie (Style harmonisé)
======================================*/
.cta--offer__price_economy {
  align-items: center;
  gap: 8px;
}

.price-box {
  display: flex;
  align-items: baseline;
  justify-content: center;
  gap: 2px;
}

.price-value {
  color: var(--color-text-dark);
  font-size: 2.2rem;
  font-weight: 600;
  letter-spacing: -0.02em;
  margin: 0;
}

.price-unit {
  color: var(--color-text-light);
  font-size: 0.9rem;
  font-weight: 500;
}

.savings-pill {
  padding: 4px 12px;
  border-radius: var(--radius-pill);
  font-size: 0.85rem;
  font-weight: 500;
  display: inline-block;
}

/*======================================
  Boutons (Harmonisés)
======================================*/
.btn-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 24px;
  font-family: var(--font-primary);
  font-weight: 600;
  font-size: 1rem;
  border: none;
  border-radius: var(--radius-pill);
  cursor: pointer;
  color: white;
  transition: all 0.2s ease;
  box-sizing: border-box; /* Assure que le padding n'explose pas la taille */
}

.btn-cta svg {
  width: 1.2em;
  height: 1.2em;
}

/* Bouton Primaire avec effet de lumière */
.btn-cta--primary {
  background-color: var(--color-primary);
  position: relative;
  overflow: hidden;
}

.btn-cta--primary:hover:not(.btn-cta-disabled) {
  background-color: var(--color-primary-hover);
}

.btn-cta--primary::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 50%;
  height: 100%;
  background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.4) 50%, rgba(255, 255, 255, 0) 100%);
  transform: skewX(-20deg);
  transition: left 0.6s ease-in-out;
}

.btn-cta--primary:not(.btn-cta-disabled):hover::after {
  left: 150%;
}

/* Bouton Secondaire */
.btn-cta--secondary {
  background-color: var(--color-secondary);
}

.btn-cta--secondary:hover:not(.btn-cta-disabled) {
  background-color: var(--color-secondary-hover);
}

/* Bouton Gris (Documents) - Désormais de la même taille globale */
.btn-cta--grey {
  color: var(--color-text-gray);
  border: 1px solid var(--color-border);
  background: var(--color-bg-gray-light);
}

.btn-cta--grey:hover:not(.desactivate) {
  background-color: var(--color-border);
  color: var(--color-text-dark);
}

/* Etats désactivés */
.btn-cta-disabled,
.btn-cta-disabled:hover {
  background-color: var(--color-border) !important;
  color: var(--color-text-light) !important;
  cursor: not-allowed;
  pointer-events: none;
}

.btn-cta--grey.desactivate {
  color: var(--color-text-light);
  background: transparent;
  border-color: var(--color-border);
  cursor: not-allowed;
  pointer-events: none;
}

/*======================================
  Responsive Mobile
======================================*/
@media screen and (max-width: 768px) {
  .cta-offer {
    align-items: center;
    padding: var(--spacing);
  }
  .cta--offer__documents {
    align-self: center;
    margin-bottom: var(--spacing-half);
  }
  .band {
    grid-template-columns: 1fr;
    grid-template-rows: auto auto auto;
    text-align: center;
    gap: var(--spacing);
  }
  .band-item-left, .band-item-right {
    align-items: center;
  }
  .btn-cta {
    width: 100%;
  }
}

